/**
 * @brief Counts the number of elements in a given range of an array whose value is equal to their frequency in that range.
 *
 * @param start The starting index of the range (inclusive).
 * @param end The ending index of the range (inclusive).
 * @param arr The input vector of integers.
 * @return The count of numbers `x` where `x` is equal to its frequency in the subarray `arr[start...end]`.
 */
int solveQuery(int start, int end, const std::vector<int>& arr) {
    std::unordered_map<int, int> frequency;
    // Calculate the frequency of each number in the given range [start, end]
    for (int i = start; i <= end; ++i) {
        frequency[arr[i]]++;
    }
    int count = 0;
    // Iterate through the frequency map
    // The pair consists of <number, its_frequency>
    for (const auto& pair : frequency) {
        // Check if the number (key) is equal to its frequency (value)
        if (pair.first == pair.second) {
            count++;
        }
    }
    return count;
}

