// A recursive binary search function. It returns
// the index of x in given array arr[l..r] if present,
// otherwise returns -1
int binarySearch(const std::vector<int>& arr, int l, int r, int x) {
    if (r >= l) {
        int mid = l + (r - l) / 2;
        // If the element is present at the middle itself
        if (arr[mid] == x) {
            return mid;
        }
        // If the element is smaller than mid, then it can only
        // be present in the left subarray
        if (arr[mid] > x) {
            return binarySearch(arr, l, mid - 1, x);
        }
        // Else the element can only be present in the right subarray
        return binarySearch(arr, mid + 1, r, x);
    }
    // We reach here when the element is not present in the array
    return -1;
}

