/**
 * @brief Function to find the ceiling of x in a sorted array.
 * The ceiling is the smallest element in the array greater than or equal to x.
 *
 * @param arr The sorted input array (as a vector).
 * @param low The starting index of the search range.
 * @param high The ending index of the search range.
 * @param x The element to find the ceiling for.
 * @return The index of the ceiling of x, or -1 if no ceiling exists.
 */
int ceilSearch(const std::vector<int>& arr, int low, int high, int x) {
    // Base case: If x is smaller than or equal to the first element,
    // the ceiling is the first element.
    if (x <= arr[low]) {
        return low;
    }
    // Base case: If x is greater than the last element,
    // there is no ceiling in the array.
    if (x > arr[high]) {
        return -1;
    }
    // Calculate the middle index to divide the array.
    // Using low + (high - low) / 2 to avoid potential integer overflow.
    int mid = low + (high - low) / 2;
    // If x is found at mid, mid is the ceiling.
    if (arr[mid] == x) {
        return mid;
    }
    // If x is greater than the middle element, the ceiling must be in the right half.
    else if (arr[mid] < x) {
        // If x is between arr[mid] and arr[mid+1], then arr[mid+1] is the ceiling.
        if (mid + 1 <= high && x <= arr[mid + 1]) {
            return mid + 1;
        } else {
            // Otherwise, search recursively in the right subarray.
            return ceilSearch(arr, mid + 1, high, x);
        }
    }
    // If x is smaller than the middle element, the ceiling is either arr[mid]
    // or an element in the left half.
    else { // arr[mid] > x
        // If x is between arr[mid-1] and arr[mid], then arr[mid] is the ceiling.
        if (mid - 1 >= low && x > arr[mid - 1]) {
            return mid;
        } else {
            // Otherwise, search recursively in the left subarray.
            return ceilSearch(arr, low, mid - 1, x);
        }
    }
}

