/**
 * @brief Checks if a circle is completely contained within an annulus (a ring-shaped region).
 * 
 * The annulus is centered at the origin (0,0) with an outer radius 'r' and an inner radius 'R'.
 * The circle to be checked has its center at (x1, y1) and a radius of 'r1'.
 * 
 * @param r The outer radius of the annulus.
 * @param R The inner radius of the annulus.
 * @param r1 The radius of the circle to check.
 * @param x1 The x-coordinate of the center of the circle to check.
 * @param y1 The y-coordinate of the center of the circle to check.
 * @return true if the circle is completely within the annulus, false otherwise.
 */
bool checkcircle(int r, int R, int r1, int x1, int y1) {
    // Calculate the square of the distance from the origin to the center of the small circle.
    // Use `long long` for the intermediate calculation to prevent potential integer overflow.
    long long dist_squared = static_cast<long long>(x1) * x1 + static_cast<long long>(y1) * y1;
    // Calculate the distance and truncate it to an integer, mimicking the Python `int()` behavior.
    int dis = static_cast<int>(std::sqrt(dist_squared));
    // The small circle is inside the annulus if:
    // 1. Its innermost point (dis - r1) is outside or on the inner ring (R).
    // 2. Its outermost point (dis + r1) is inside or on the outer ring (r).
    return (dis - r1 >= R && dis + r1 <= r);
}

