    // Iterate through all possible split points for four non-empty substrings.
    // i, j, k are the start indices of the 2nd, 3rd, and 4th substrings.
    for (size_t i = 1; i < n; ++i) {
        for (size_t j = i + 1; j < n; ++j) {
            for (size_t k = j + 1; k < n; ++k) {
                // Create the four substrings based on the split points.
                // s.substr(pos, len)
                std::string s1 = s.substr(0, i);
                std::string s2 = s.substr(i, j - i);
                std::string s3 = s.substr(j, k - j);
                std::string s4 = s.substr(k); // from index k to the end
                // Check if all four substrings are distinct.
                if (s1 != s2 && s1 != s3 && s1 != s4 &&
                    s2 != s3 && s2 != s4 &&
                    s3 != s4) {
                    return true;
                }
            }
        }
    }
    // If no such partition is found after checking all possibilities.
    return false;
}

