/**
 * @brief Checks if the elements in a vector are consecutive.
 * 
 * This function determines if the elements of an integer vector form a
 * consecutive sequence. For example, {5, 2, 3, 4} is consecutive, but
 * {5, 2, 3, 6} or {5, 2, 3, 3} are not.
 * 
 * @param arr The input vector of integers. The vector is passed by const reference
 *            to avoid copying.
 * @param n The number of elements in the vector.
 * @return true if the elements are consecutive, false otherwise.
 */
bool areConsecutive(const std::vector<int>& arr, int n) {
    // If the vector has fewer than 1 element, they cannot be consecutive.
    if (n < 1) {
        return false;
    }
    // Find the minimum and maximum elements in the vector.
    int Min = *std::min_element(arr.begin(), arr.end());
    int Max = *std::max_element(arr.begin(), arr.end());
    // For elements to be consecutive, the difference between the maximum and minimum
    // element plus 1 must be equal to the number of elements.
    // This also handles the case of duplicate elements.
    if (Max - Min + 1 == n) {
        // We use a boolean vector to mark visited elements to check for duplicates.
        std::vector<bool> visited(n, false);
        for (int i = 0; i < n; ++i) {
            // If an element is found that has been visited before, it's a duplicate.
            // The index is calculated by subtracting the minimum value to map the
            // element to the range [0, n-1].
            if (visited[arr[i] - Min]) {
                return false;
            }
            // Mark the element as visited.
            visited[arr[i] - Min] = true;
        }
        // If the loop completes, all elements are distinct and form a consecutive sequence.
        return true;
    }
    // If (Max - Min + 1) is not equal to n, they cannot be consecutive.
    return false;
}

