// Function to check if a given array can represent
// preorder traversal of a Binary Search Tree
bool canRepresentBST(const std::vector<int>& pre, int n) {
    // Create an empty stack
    std::stack<int> s;
    // Initialize current root as minimum possible value
    int root = INT_MIN;
    // Traverse given array
    for (int i = 0; i < n; ++i) {
        // If we find a node who is on the right side
        // and smaller than root, return false
        if (pre[i] < root) {
            return false;
        }
        // If pre[i] is in the right subtree of stack top,
        // Keep removing items smaller than pre[i]
        // and make the last removed item as the new root.
        while (!s.empty() && s.top() < pre[i]) {
            root = s.top();
            s.pop();
        }
        // At this point either stack is empty or pre[i]
        // is smaller than root, push pre[i]
        s.push(pre[i]);
    }
    return true;
}

