// Function to find the number of digits in n!
int findDigits(int n) {
    // Factorial is not defined for negative numbers
    if (n < 0) {
        return 0;
    }
    // Base case: 0! = 1, 1! = 1. Both have 1 digit.
    if (n <= 1) {
        return 1;
    }
    // Kamenetsky's formula states that the number of digits in n!
    // is floor(log10(n!)) + 1.
    // We can use the property of logarithms: log(a*b) = log(a) + log(b).
    // So, log10(n!) = log10(1) + log10(2) + ... + log10(n).
    // We sum the logarithms from 2 to n (since log10(1) is 0).
    double digits = 0;
    for (int i = 2; i <= n; i++) {
        digits += std::log10(i);
    }
    // Return the floor of the sum of logarithms plus 1.
    return static_cast<int>(std::floor(digits)) + 1;
}

