 */
std::string decToBin(int n) {
    // Handle the edge case of 0.
    if (n == 0) {
        return "0";
    }
    std::string bin = "";
    while (n > 0) {
        // Check the least significant bit.
        if ((n & 1) == 0) {
            // If the LSB is 0, prepend '0' to the string.
            bin = '0' + bin;
        } else {
            // If the LSB is 1, prepend '1' to the string.
            bin = '1' + bin;
        }
        // Right shift n to process the next bit.
        n = n >> 1;
    }
    return bin;
}

