    //   The XOR of their sign bits will be 1. This makes the result (x ^ y) a negative number.
    // - If x and y have the same sign, their sign bits are the same (both 0 or both 1).
    //   The XOR of their sign bits will be 0. This makes the result (x ^ y) a non-negative number.
    //
    // Therefore, checking if (x ^ y) is negative is a concise way to determine if x and y
    // have opposite signs.
    return (x ^ y) < 0;
}
