/**
 * @brief Checks if a square matrix is diagonally dominant.
 * 
 * A matrix is diagonally dominant if for every row, the absolute value of the
 * diagonal element is greater than or equal to the sum of the absolute values
 * of all other (off-diagonal) elements in that row. This function performs
 * a direct translation of the provided Python logic.
 * 
 * @param m A square matrix represented as a vector of vectors of doubles.
 *          Using a const reference to avoid copying the matrix.
 * @param n The number of rows and columns in the matrix.
 * @return true if the matrix is diagonally dominant, false otherwise.
 */
bool isDDM(const std::vector<std::vector<double>>& m, int n) {
    // Iterate over each row of the matrix
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        // Calculate the sum of absolute values of all elements in the current row
        for (int j = 0; j < n; ++j) {
            sum = sum + std::abs(m[i][j]);
        }
        // Subtract the absolute value of the diagonal element to get the sum of off-diagonal elements
        sum = sum - std::abs(m[i][i]);
        // If the absolute value of the diagonal element is less than the sum
        // of the absolute values of off-diagonal elements for any row, the matrix
        // is not diagonally dominant.
        if (std::abs(m[i][i]) < sum) {
            return false;
        }
    }
    // If all rows satisfy the condition, the matrix is diagonally dominant.
    return true;
}

