    }
    // Otherwise, return the maximum of two cases:
    // 1. The n-th item is included: its value is added, and we recur for the
    //    remaining n-1 items with reduced capacity.
    // 2. The n-th item is not included: we recur for the remaining n-1 items
    //    with the same capacity.
    else {
        return std::max(
            val[n - 1] + knapSack(W - wt[n - 1], wt, val, n - 1),
            knapSack(W, wt, val, n - 1)
