// Function to count the number of ways friends can be paired up or remain single.
long long countFriendsPairings(int n) {
    // Create a DP table to store results for subproblems.
    // The size is n+1 to store results from 0 to n.
    std::vector<long long> dp(n + 1);
    // Fill the DP table in a bottom-up manner.
    for (int i = 0; i <= n; i++) {
        // Base cases
        if (i <= 2) {
            dp[i] = i;
        } else {
            // Recurrence relation:
            // For the i-th person, there are two choices:
            // 1) The i-th person remains single. The number of ways is then the same as for i-1 people, which is dp[i-1].
            // 2) The i-th person pairs up with one of the other i-1 people.
            //    We can choose a partner in (i-1) ways. After pairing, we are left with i-2 people.
            //    The number of ways for this case is (i-1) * dp[i-2].
            dp[i] = dp[i - 1] + (long long)(i - 1) * dp[i - 2];
        }
    }
    return dp[n];
}

