int kthLargestSum(std::vector<int>& arr, int n, int k) {
    // Create a prefix sum array.
    // sum[i] will store the sum of elements from arr[0] to arr[i-1].
    std::vector<int> sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
