// The function calculates the number of occurrences of the subsequence "ab"
// in a string 's' repeated 'K' times.
long long countOccurrences(std::string s, long long K) {
    long long n = s.length();
    long long c1 = 0; // count of 'a's in the original string s
    long long c2 = 0; // count of 'b's in the original string s
    long long C = 0;  // count of "ab" subsequences in the original string s
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'a') {
            c1++;
        }
        if (s[i] == 'b') {
            c2++;
            // For each 'b', the number of "ab" subsequences formed
            // is equal to the number of 'a's seen so far.
            C += c1;
        }
    }
    // The total number of "ab" subsequences in the final string (s repeated K times)
    // is the sum of two parts:
    // 1. Subsequences where 'a' and 'b' are from the same block of 's'.
    //    There are K blocks, so this is C * K.
    // 2. Subsequences where 'a' is from block 'i' and 'b' is from block 'j' where i < j.
    //    The number of 'a's in any block is c1. The number of 'b's is c2.
    //    The number of pairs of blocks (i, j) with i < j is the sum 1+2+...+(K-1), which is K*(K-1)/2.
    //    So, this part is (K * (K - 1) / 2) * c1 * c2.
    return C * K + (K * (K - 1) / 2) * c1 * c2;
}

