 *
 * This function uses a modified Sieve of Eratosthenes to pre-calculate the number of
 * distinct prime factors for all integers up to n. It then iterates through the
 * specified range [m, n] to find the number with the highest count.
 *
 * @param m The starting integer of the range (inclusive).
 * @param n The ending integer of the range (inclusive).
 * @return The integer in the range [m, n] with the most distinct prime factors.
 *         If there's a tie, the smallest such number is returned.
 */
int maximumNumberDistinctPrimeRange(int m, int n) {
    // A vector to store the count of distinct prime factors for each number.
    std::vector<int> factorCount(n + 1, 0);
    // A boolean vector to mark prime numbers (part of the Sieve).
    std::vector<bool> prime(n + 1, true);
    // Modified Sieve of Eratosthenes to count distinct prime factors.
    for (int i = 2; i <= n; ++i) {
        // If i is a prime number.
        if (prime[i]) {
            // A prime number has one distinct prime factor (itself).
            factorCount[i] = 1;
            // Iterate through all multiples of i.
            for (int j = i * 2; j <= n; j += i) {
                // Increment the distinct prime factor count for the multiple.
                factorCount[j]++;
                // Mark the multiple as not prime.
                prime[j] = false;
            }
        }
    }
    // Find the number with the maximum distinct prime factors in the range [m, n].
    int max_factors = factorCount[m];
    int result_num = m;
    for (int i = m; i <= n; ++i) {
        if (factorCount[i] > max_factors) {
            max_factors = factorCount[i];
            result_num = i;
        }
    }
    return result_num;
}

