// Function to find the minimum number of squares that can tile a rectangle
int minimumSquare(int a, int b) {
    int result = 0;
    // Ensure 'a' is always the larger side
    if (a < b) {
        std::swap(a, b);
    }
    // This is a variation of the Euclidean algorithm.
    // At each step, we cut out the maximum number of squares of the largest possible size.
    while (b > 0) {
        // Add the number of squares of side 'b' that can be cut from the 'a x b' rectangle
        result += a / b;
        // Calculate the remaining rectangle's dimensions
        int rem = a % b;
        a = b;
        b = rem;
    }
    return result;
}

