/**
 * @brief Calculates the maximum average value of a path in a grid.
 *
 * This function finds the path from the top-left corner (0,0) to the
 * bottom-right corner (N-1, N-1) of a grid with the maximum sum of costs.
 * It is assumed that movement is restricted to only down and right.
 * The function then returns the average cost of this path.
 *
 * @param cost A 2D vector representing the cost grid.
 * @param N The dimension of the square grid (N x N).
 * @return The maximum average cost of a path from (0,0) to (N-1, N-1).
 */
double maxAverageOfPath(const std::vector<std::vector<int>>& cost, int N) {
    // Create a DP table to store the maximum cost to reach cell (i, j)
    std::vector<std::vector<int>> dp(N, std::vector<int>(N, 0));
    // Base case: The cost to reach the starting cell (0, 0) is its own cost
    dp[0][0] = cost[0][0];
    // Initialize the first column of the DP table
    // To reach (i, 0), we can only come from (i-1, 0)
    for (int i = 1; i < N; ++i) {
        dp[i][0] = dp[i - 1][0] + cost[i][0];
    }
    // Initialize the first row of the DP table
    // To reach (0, j), we can only come from (0, j-1)
    for (int j = 1; j < N; ++j) {
        dp[0][j] = dp[0][j - 1] + cost[0][j];
    }
    // Fill the rest of the DP table using the recurrence relation
    for (int i = 1; i < N; ++i) {
        for (int j = 1; j < N; ++j) {
            // The max cost to reach (i, j) is the max of coming from the top or left,
            // plus the cost of the current cell.
            dp[i][j] = std::max(dp[i - 1][j], dp[i][j - 1]) + cost[i][j];
        }
    }
    // The total sum of the maximum cost path is stored in dp[N-1][N-1].
    // Any path from (0,0) to (N-1,N-1) by moving only down or right
    // will have a length of (N-1) + (N-1) + 1 = 2*N - 1 cells.
    // We cast the total cost to double to ensure floating-point division.
    return static_cast<double>(dp[N - 1][N - 1]) / (2 * N - 1);
}

