 *        and negative numbers are at odd indices.
 * 
 * @param a The vector of integers to be rearranged (passed by reference).
 * @param size The number of elements in the vector.
 */
void rearrange(std::vector<int>& a, int size) {
    int positive = 0;
    int negative = 1;
    while (true) {
        // Find the first even index that holds a negative number.
        while (positive < size && a[positive] >= 0) {
            positive += 2;
        }
        // Find the first odd index that holds a positive number.
        while (negative < size && a[negative] <= 0) {
            negative += 2;
        }
        // If both pointers are within the array bounds, it means we have found
        // a misplaced positive and a misplaced negative number. Swap them.
        if (positive < size && negative < size) {
            std::swap(a[positive], a[negative]);
        }
        // If either pointer goes out of bounds, the rearrangement is complete.
        else {
            break;
        }
    }
}

