/**
 * @brief Converts a decimal integer to its binary representation.
 * 
 * The function takes an integer N and returns its binary equivalent
 * represented as a long long integer. For example, if N is 10,
 * its binary is 1010, and the function will return the integer 1010.
 * 
 * @param N The decimal integer to convert.
 * @return A long long integer representing the binary number.
 */
long long decimalToBinary(int N) {
    long long B_Number = 0;
    int cnt = 0;
    while (N != 0) {
        int rem = N % 2;
        // std::pow returns a double, so we cast it to long long.
        long long c = static_cast<long long>(std::pow(10, cnt));
        B_Number += rem * c;
        N /= 2; // Integer division in C++
        cnt++;
    }
    return B_Number;
}

