 * @brief Finds the minimum angle that can be formed.
 * This function implements a sliding window approach to find a contiguous
 * subarray whose sum is closest to 180.
 *
 * @param arr A vector of integers representing angles.
 * @param n The number of elements in the vector.
 * @return The minimum possible angle difference, scaled by 2.
 */
int findMinimumAngle(const std::vector<int>& arr, int n) {
    int l = 0;
    int _sum = 0;
    int ans = 360;
    for (int i = 0; i < n; ++i) {
        // Add the current element to the window sum
        _sum += arr[i];
        // Shrink the window from the left if the sum is 180 or more
        while (_sum >= 180) {
            ans = std::min(ans, 2 * std::abs(180 - _sum));
            _sum -= arr[l];
            l++;
        }
        // Also check the minimum for the current window sum (which is < 180)
        ans = std::min(ans, 2 * std::abs(180 - _sum));
    }
    return ans;
}

