void worstFit(std::vector<int>& blockSize, int m, const std::vector<int>& processSize, int n) {
    // Stores block id of the block allocated to a process
    std::vector<int> allocation(n, -1);
    // Pick each process and find the worst fit block for it
    for (int i = 0; i < n; i++) {
        // Find the best fit block for the current process
        int wstIdx = -1;
        for (int j = 0; j < m; j++) {
