// Note: The array elements are assumed to be non-negative.
// The type 'long long' is used for the array elements to prevent overflow
// during the encoding step, as arr[i] can become large.
void rearrange(std::vector<long long>& arr, int n) {
    // Index of the largest element (from the end)
    int max_idx = n - 1;
    // Index of the smallest element (from the beginning)
    int min_idx = 0;
    // A value that is greater than any element in the original array.
    // This is used as a multiplier to store two numbers at a single index.
    long long max_elem = arr[n - 1] + 1;
    // Iterate through the array to encode the new arrangement.
    for (int i = 0; i < n; ++i) {
        // At even positions, we place the largest remaining element.
        if (i % 2 == 0) {
            arr[i] += (arr[max_idx] % max_elem) * max_elem;
            max_idx--;
        }
        // At odd positions, we place the smallest remaining element.
        else {
            arr[i] += (arr[min_idx] % max_elem) * max_elem;
            min_idx++;
        }
    }
    // Iterate through the array again to decode the values.
    // The rearranged value is obtained by integer division.
    for (int i = 0; i < n; ++i) {
        arr[i] = arr[i] / max_elem;
    }
}

