void insertionSortRecursive(std::vector<int>& arr, int n) {
    // Base case: If array has 1 or 0 elements, it is already sorted.
    if (n <= 1) {
        return;
    }
    // Sort the first n-1 elements recursively.
    insertionSortRecursive(arr, n - 1);
    // Insert the last element (arr[n-1]) into its correct position
    // in the sorted part of the array (arr[0...n-2]).
    int last = arr[n - 1];
    int j = n - 2;
    // Move elements of arr[0...n-2] that are greater than 'last'
    // to one position ahead of their current position.
    while (j >= 0 && arr[j] > last) {
        arr[j + 1] = arr[j];
        j = j - 1;
    }
    arr[j + 1] = last;
}

