 * @return The maximum possible score for the subproblem defined by [low, high].
 */
long long solve(std::vector<std::vector<long long>>& dp, const std::vector<int>& a, int low, int high, int turn) {
    if (low == high) {
        return static_cast<long long>(a[low]) * turn;
