    dp[low][high] = std::max(
        static_cast<long long>(a[low]) * turn + solve(dp, a, low + 1, high, turn + 1),
        static_cast<long long>(a[high]) * turn + solve(dp, a, low, high - 1, turn + 1)
    );
    return dp[low][high];
}

