 *
 * @param arr The array to insert into.
 * @param n The current number of elements in the array.
 * @param key The key to be inserted.
 * @param capacity The maximum capacity of the array.
 * @return The new size of the array after insertion.
 */
int insertSorted(int* arr, int n, int key, int capacity) {
    // Cannot insert if the array is already full
    if (n >= capacity) {
        return n;
    }
    int i = n - 1;
    // Find the position to insert the key by shifting
    // elements greater than the key to the right.
    while (i >= 0 && arr[i] > key) {
        arr[i + 1] = arr[i];
        i--;
    }
    // Insert the key at the correct position.
    arr[i + 1] = key;
    // Return the new size of the array.
    return (n + 1);
}

