            b = b >> 1;
        }
        // Now both a and b are odd. Swap if necessary so a <= b.
        if (a > b) {
            std::swap(a, b);
        }
        // b becomes b - a (which is even)
        b = b - a;
    }
    // Restore the common factors of 2
    return (a << k);
}

