/**
 * @brief Swaps n bits of an integer x starting from position p1 with n bits
 *        starting from position p2.
 *
 * @param x The original number.
 * @param p1 The starting position of the first block of bits.
 * @param p2 The starting position of the second block of bits.
 * @param n The number of bits to swap in each block.
 * @return The number after swapping the specified bits.
 */
unsigned int swapBits(unsigned int x, unsigned int p1, unsigned int p2, unsigned int n) {
    // Isolate the first set of n bits.
    // (1U << n) - 1 creates a mask of n ones.
    // Shifting x right by p1 and ANDing with the mask extracts the bits.
    unsigned int set1 = (x >> p1) & ((1U << n) - 1);
    // Isolate the second set of n bits.
    unsigned int set2 = (x >> p2) & ((1U << n) - 1);
    // Use XOR to find the bits that are different between the two sets.
    // If a bit is the same in both sets, the result is 0.
    // If a bit is different, the result is 1.
    unsigned int xor_of_sets = (set1 ^ set2);
    // Create a mask to flip the bits in the original number.
    // This mask has 1s at every position that needs to be flipped.
    // We shift the differing bits back to their original positions (p1 and p2).
    unsigned int mask = (xor_of_sets << p1) | (xor_of_sets << p2);
    // XOR the original number with the mask. This flips only the bits
    // that were different between the two sets, effectively swapping them.
    unsigned int result = x ^ mask;
    return result;
}

