/**
 * @brief Checks if a number is a multiple of 3 using a bit manipulation algorithm.
 * 
 * This function is based on the property that a number is divisible by 3 if and only if
 * the absolute difference between the count of set bits at odd positions and the count
 * of set bits at even positions is divisible by 3. The function applies this
 * property recursively.
 * 
 * @param n The integer to check.
 * @return 1 if n is a multiple of 3, 0 otherwise.
 */
int isMultipleOf3(int n) {
    int odd_count = 0;
    int even_count = 0;
    // Handle negative numbers by taking their absolute value
    if (n < 0) {
        n = -n;
    }
    // Base case: 0 is a multiple of 3
    if (n == 0) {
        return 1;
    }
    // Base case: 1 is not a multiple of 3
    if (n == 1) {
        return 0;
    }
    // Loop until the number becomes 0
    while (n) {
        // If the bit at the odd position (2^0, 2^2, ...) is set, increment odd_count
        if (n & 1) {
            odd_count++;
        }
        // If the bit at the even position (2^1, 2^3, ...) is set, increment even_count
        if (n & 2) {
            even_count++;
        }
        // Right shift by 2 to process the next pair of bits
        n = n >> 2;
    }
    // Recur with the absolute difference of the counts
    return isMultipleOf3(abs(odd_count - even_count));
}

